var e=[{id:`L3_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`으아아, 위험했다.`,JPN:`うあぁ、危なかった。`,ENG:`Whoa, that was close.`,TWN:`唉，好險。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`무턱대고 바이크 흔적만 쫓다가 벌써 죽을 고비를 몇 번이나 넘긴 거야.`,JPN:`がむしゃらにバイクの後を追ったせいで、何回も死にかけたよ。`,ENG:`I don't know how many times I almost died by blindly chasing the bike tracks.`,TWN:`盲目追隨摩托車胎痕已經讓我幾次險些喪命。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`그런 엄청난 일을 다 겪고 나서도, 장비 도움이 없으면 실력은 예전이랑 똑같구나.`,JPN:`あんな凄いことを経験したのに、装備の助けが無ければ、実力は昔のままなんだよな。`,ENG:`I guess, even after all I've been through, I'm the same without the help of my gear.`,TWN:`明明經歷了這麼多，我的實力如果沒有裝備加持仍然沒什麼改變。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`솔직히 지금도… 번쩍하고 누가 날 도와주러 오는 상상이나 하고 있잖아.`,JPN:`正直今も……誰かがパッと現れて、助けてくれることを想像してたりして。`,ENG:`Even now... I'm just waiting for someone to randomly appear and save me.`,TWN:`老實說，即使是現在……我還在幻想著有人突然冒出來救我。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`호라이즌 씨라거나… 노르드나빅의 군인분들이나… 아니면 하늘을 나는 엄청나게 센 호라이즌 씨…`,JPN:`ホライズンさんとか……ノルドナビックの軍人さんとか……それとも空を飛ぶめっちゃ強いホライズンさん……`,ENG:`Maybe someone like Horizon... or the Nordnavik soldiers... or maybe the super strong version of flying Horizon...`,TWN:`比如地平線……或者是諾爾德萊比的士兵……或者是在天上飛的超強地平線……`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`그렇게 도망쳐 놓고서 또 기적을 바라다니. 나도 참 염치가 없지.`,JPN:`あんなに逃げ回ってそれでも奇跡を願うとは。私ってバカだな。`,ENG:`Can't believe I'm hoping for a miracle again after all those times I ran away. Didn't know I was that shameless.`,TWN:`只顧逃跑還渴望奇蹟，我真是不要臉。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`하지만 그렇다곤 해도…`,JPN:`でも、そうだったとしても……`,ENG:`But even so...`,TWN:`但即便如此……`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`…이번엔 이상하게, 도망치고 싶은 마음은 들지 않아.`,JPN:`……なぜか今は、逃げたいと思わない。`,ENG:`...It feels different this time. I don't want to make a run for it.`,TWN:`……這次我卻不想逃跑了，好奇怪。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`윽! 저리 좀 가!!`,JPN:`うっ！　あっち行って！！`,ENG:`Ngh! Go away!!`,TWN:`呃！離我遠點！！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`아까보다 침식체가 많아. 점점 가까워지고 있어.`,JPN:`さっきより侵食体が多い。どんどん近づいてる。`,ENG:`There are more C.O.s than before. I must be getting close.`,TWN:`這裡的侵蝕體比剛才還多，還越來越靠近。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`…무사해야 돼요.`,JPN:`……どうか無事でありますように。`,ENG:`...Please, be safe.`,TWN:`……希望平安無事。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`여기도 침식체가 있다고?`,JPN:`ここにも侵食体がいるって？`,ENG:`C.O.s are here as well?`,TWN:`這裡也有侵蝕體？`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`빠져나갈 틈 없이 포위당했어.`,JPN:`囲まれて逃げる隙がない。`,ENG:`I'm completely surrounded.`,TWN:`我被徹底包圍了。`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`큭?!`,JPN:`くっ！？`,ENG:`Kgh?!`,TWN:`咳？！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_HATE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`…찾았다.`,JPN:`……見ツケタ。`,ENG:`...Found you.`,TWN:`……找到了。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};